choose.when:
SELECT TO_CHAR(TO_DATE(SUBSTR(A.SN_REQ_DY_TM,1,8),'YYYYMMDD'),'YYYY-MM-DD') AS SN_REQ_DY_TM ,A.INST_CCD ,GET_CODE_NAME('S041', A.SN_PRGRS_CCD) AS ACT_NAME ,DECODE(A.INST_CCD, 'CTR', 'CTR', 'KYC', C.RS32_2, 'STR', NVL(B.RULE_GB,C.RS32_2)) AS RULE_GB ,DECODE(A.INST_CCD, 'CTR 기준금액', 'KYC', C.RS32_2, 'STR', NVL(B.RULE_DESC, C.RS32_2)) AS RULE_DESC ,'조회' AS UPD_HIS ,'조회' AS APP_HIS ,CASE WHEN A.SN_END_DY_TM IS NOT NULL THEN TO_CHAR(TO_DATE(SUBSTR(A.SN_END_DY_TM,1,8),'YYYYMMDD'),'YYYY-MM-DD') END AS SN_END_DY_TM ,CASE WHEN A.SN_PRGRS_CCD = '9' AND E.RS32_1=D.RS31_6 AND E.RS34_U = 2 THEN TO_CHAR(TO_DATE(SUBSTR(D.RS31_Y,1,8),'YYYYMMDD'),'YYYY-MM-DD') END AS DEPLOY_DT ,A.INST_ID ,C.RS31_1 ,C.RS32_1 ,C.RS32_3 ,DECODE(A.INST_CCD, 'CTR', 'CTR기준금액', A.RULE_ID) AS RULE_ID ,B.RT30_1 AS RS20_1 FROM NIC58B A ,( SELECT '['||Y.MA01_6||'] '|| X.BIZ_NM AS RULE_GB ,X.BIZ_DESC AS RULE_DESC ,Y.MA01_6 ,Y.RT30_1 FROM C_BIZ X ,MMA010TB Y ,C_PKG_BIZ_MAP Z WHERE X.BIZ_ID = Y.RT30_1 AND X.BIZ_ID = Z.BIZ_ID AND Z.PKG_ID = '6' ) B ,( SELECT X.INST_ID, Z.ACT_NAME FROM WF_PROC_INSTANCE X ,WF_WORKLIST Y ,WF_ACT Z WHERE X.WORK_ID = Y.WORK_ID AND Y.ACT_ID = Z.ACT_ID ) F ,BRS320TB C ,BRS310TB D ,BRS340TB E WHERE A.RULE_ID = B.MA01_6(+) AND A.INST_ID = F.INST_ID AND (DECODE(A.INST_CCD, 'STR', '기준DATA_'||A.RULE_ID, 'CTR기준금액') = C.RS32_2 OR A.RULE_ID = TO_CHAR(C.RS31_1)) AND C.RS31_1 = D.RS31_1 AND D.RS31_1 = E.RS31_1 AND C.RS32_1 = A.RULE_UPD_MAJ_VER AND D.RS31_3 = A.RULE_UPD_MAJ_VER AND E.RS32_1 = A.RULE_UPD_MAJ_VER AND E.RS34_1 = A.RULE_UPD_MIN_VER
AND A.INST_CCD = #{INST_CCD}
AND SUBSTR(A.SN_REQ_DY_TM,1,8) BETWEEN #{stDate} AND #{edDate}
AND A.SN_PRGRS_CCD = #{SN_PRGRS_CCD}
AND F.INST_ID IS NOT NULL
ORDER BY A.INST_ID DESC

mapper.update:
UPDATE NIC58B
   SET SN_PRGRS_CCD = #{SN_PRGRS_CCD}
      ,SN_END_DY_TM = TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
 WHERE INST_ID = #{INST_ID}

UPDATE NIC58B
   SET SN_PRGRS_CCD = #{SN_PRGRS_CCD}
      ,SN_DEL_P_ENO = #{SN_DEL_P_ENO}
      ,SN_DEL_DY_TM = #{SN_DEL_DY_TM}
 WHERE INST_ID = #{INST_ID}

