SELECT TO_DATE(MA22_1, 'YYYY-MM-DD') AS BASE_DT        -- 추출일자
      ,MA22_3 AS EXCT_CNT
  FROM MMA220TB
 WHERE MA20_1  =  #{MA01_6}        --PARAM
   AND MA20_2 = #{WORK_DT}
   AND MA20_3 = #{INDV_CORP_CD}

mapper.update:
UPDATE BRS340TB
   SET RS34_2 = 0
 WHERE RS31_1 = #{RULE_NO}
   AND RS32_1 = #{MAJ_A}
   AND RS34_1 = #{MIN_A}

mapper.select:
SELECT * 
  FROM RA_ITEM 
 WHERE RA_ITEM_CD = #{RA_ITEM_CD}

SELECT A.APP_NO ,TO_CHAR(TO_DATE(A.APP_DT, 'YYYYMMDD'), 'YYYY-MM-DD') AS APP_DT ,B.SCNR_ID ,B.SCNR_CCD ,A.SN_CCD ,'[' || B.SCNR_ID || ']' || B.SCNR_NM AS CATEGORY ,'조회' AS CHANGE_HISTORY ,'조회' AS APPROVAL_HISTORY ,B.SCNR_NM ,A.RSN_CNTNT FROM AML_APPR A INNER JOIN TMS_APPL B ON A.APP_NO = B.LST_APP_NO INNER JOIN TMS_REQ C ON B.SCNR_ID = C.SCNR_ID WHERE A.GYLJ_LINE_G_C IN ('TMS1', 'TMS2')
AND A.TARGET_ROLE_ID = #{APPR_ROLE_ID}
AND A.SN_CCD != 'E' AND A.APP_DT BETWEEN #{stDate} AND #{edDate} ORDER BY A.APP_DT DESC

SELECT *
  FROM C_GYLJ_D
 WHERE GYLJ_LINE_G_C = #{GYLJ_LINE_G_C}
   AND GYLJ_ROLE_ID = #{ROLE_ID}

mapper.update:
UPDATE AML_APPR
   SET APP_DT = TO_CHAR(SYSDATE, 'YYYYMMDD')
      ,NUM_SQ = #{NUM_SQ}
      ,SNO = #{SNO}
      ,SN_CCD = #{SN_CCD}
      ,APPR_ROLE_ID = #{ROLE_ID}
      ,TARGET_ROLE_ID = #{TARGET_ROLE_ID}
      ,RSN_CNTNT = #{APP_CNTNT jdbcType=VARCHAR}
      ,HNDL_DY_TM = SYSDATE
      ,HNDL_P_ENO = #{USER_ID}
 WHERE APP_NO = #{APP_NO}
   AND GYLJ_LINE_G_C = #{GYLJ_LINE_G_C}

