SELECT *
  FROM TMS_SET_VAL_APP_DTL
 WHERE APP_NO = #{APP_NO}

mapper.update:
MERGE
 INTO TMS_SET_VAL A
USING DUAL
   ON (A.SCNR_ID = #{SCNR_ID}
  AND A.CS_CCD = #{CS_CCD}
  AND A.SET_VAL_CD = #{SET_VAL_CD})
 WHEN MATCHED THEN
      UPDATE
         SET A.SET_VAL = #{SET_VAL}
            ,A.UPD_ID = #{USER_ID jdbcType=VARCHAR}
            ,A.UPD_DTTM = TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
 WHEN NOT MATCHED THEN
      INSERT
             (
                A.SCNR_ID
               ,A.CS_CCD
               ,A.SET_VAL_CD
               ,A.SET_VAL
               ,A.REG_ID
               ,A.REG_DTTM
             )
      VALUES
             (
                #{SCNR_ID}
               ,#{CS_CCD}
               ,#{SET_VAL_CD}
               ,#{SET_VAL}
               ,#{USER_ID jdbcType=VARCHAR}
               ,TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')
             )

mapper.select:
SELECT *
  FROM TMS_SET_VAL
 WHERE SCNR_ID = #{SCNR_ID}
